code = """import json
import pandas as pd

# Load languages
languages_file = locals()['var_function-call-17240126939060447987']
with open(languages_file, 'r') as f:
    languages_data = json.load(f)

# Load readmes
readmes_data = locals()['var_function-call-779425012540162029']
# readmes_data is already a list

# 1. Identify non-Python repos
non_python_repos = set()
for entry in languages_data:
    repo = entry['repo_name']
    desc = entry['language_description']
    # Check if Python is mentioned. 
    # The description is natural language but usually contains the language name.
    # We'll check case-insensitive.
    if 'python' not in desc.lower():
        non_python_repos.add(repo)

# 2. Filter readmes
# We are looking for proportion of *their* READMEs.
# So we only care about READMEs belonging to non_python_repos.
filtered_readmes = [r for r in readmes_data if r['sample_repo_name'] in non_python_repos]

# 3. Calculate stats
# Denominator: Number of repos in filtered_readmes
# We should count unique repos in case there are duplicates (though count(*) was 128 and list size was ~128, likely unique).
repos_with_readme = set(r['sample_repo_name'] for r in filtered_readmes)
denominator = len(repos_with_readme)

# Numerator: Number of repos with copyright in README
# If a repo has multiple READMEs (unlikely here), we count if *any* has copyright.
repos_with_copyright = set()
for r in filtered_readmes:
    repo = r['sample_repo_name']
    has_copy = r['has_copyright']
    # Check if has_copy indicates true. The query returned '0' or '1' as strings.
    if str(has_copy) == '1':
        repos_with_copyright.add(repo)

numerator = len(repos_with_copyright)

proportion = 0.0
if denominator > 0:
    proportion = numerator / denominator

print("__RESULT__:")
print(json.dumps({
    "numerator": numerator,
    "denominator": denominator,
    "proportion": proportion
}))"""

